import os
import requests
import pickle
from io import BytesIO
from dotenv import load_dotenv

load_dotenv()


class ModelLoader:
    def __init__(self):
        self.model_path = os.getenv('MODEL_PATH')
        self.model = None

    def load_model_from_cloud(self):
        response = requests.get(self.model_path)
        self.model = pickle.loads(response.content)

    def get_latest_model(self):
        files = [f for f in self.model_path.listdir() if f.endswith('.pkl')]
        files.sort(key=lambda x: x.stat().st_mtime)
        latest_model = files[-1]
        return latest_model

    def load_model(self):
        latest_model_path = self.get_latest_model()
        with open(latest_model_path, 'rb') as file:
            self.model = pickle.load(file)

    def startup(self):
        self.load_model_from_cloud()


model_loader = ModelLoader()
